'use strict';

/**
 * Module dependencies.
 * @private
 */

/**
 * Middleware loader for Express.js
 * 
 * This module is responsible for loading and initializing built-in middleware
 * components that process requests before they reach route handlers.
 * 
 * @module middleware
 */

/**
 * Initialize request and response objects with Express.js extensions
 * @public
 */
exports.init = require('./middleware/init');

/**
 * Parse query string parameters from URL into req.query object
 * @public
 */
exports.query = require('./middleware/query');

/**
 * Export middleware loader
 * @public
 */
module.exports = exports;